import { isNil } from 'lodash-es';

import { calculateTotalWidth500 } from './width-calculation.js';
import type { TruncationMode } from '../../../../../typography/text-ellipsis/TextEllipsis.js';
import { charsFontWidth12pixelsSize500Map } from '../../text-ellipsis/chars-font-width-map.js';
import { truncateString } from '../../text-ellipsis/truncate-string.js';
import { isValidNumber } from '../components/series/utils/is-valid-number.js';

/**
 * Truncates text using the header font weight (500) map.
 * Used by Header and SeriesHeader components.
 */
export const getHeaderTruncatedText = (
  text: string | undefined | null,
  maxWidth: number | undefined,
  truncationMode: TruncationMode,
) => {
  if (isNil(text)) {
    return '';
  }
  if (!isValidNumber(maxWidth)) {
    return text;
  }

  const textWidth = calculateTotalWidth500(text);
  if (textWidth <= maxWidth) {
    return text;
  }
  return truncateString(
    text,
    maxWidth,
    charsFontWidth12pixelsSize500Map,
    truncationMode,
  );
};
